(window.webpackJsonp=window.webpackJsonp||[]).push([[530],{799:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">left</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">right</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getLastMoment = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, left, right</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> maxLeft=<span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,left)\\n    <span class=\\"hljs-keyword\\">let</span> minRight=<span class=\\"hljs-built_in\\">Math</span>.min.apply(<span class=\\"hljs-built_in\\">Math</span>,right)\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max(maxLeft,n-minRight)\\n};\\n</code></pre>\\n"],"titleSlug":"last-moment-before-all-ants-fall-out-of-a-plank","hasThinking":false,"content":"<p>\u6709\u4e00\u5757\u6728\u677f\uff0c\u957f\u5ea6\u4e3a <code>n</code> \u4e2a <strong>\u5355\u4f4d</strong> \u3002\u4e00\u4e9b\u8682\u8681\u5728\u6728\u677f\u4e0a\u79fb\u52a8\uff0c\u6bcf\u53ea\u8682\u8681\u90fd\u4ee5 <strong>\u6bcf\u79d2\u4e00\u4e2a\u5355\u4f4d</strong> \u7684\u901f\u5ea6\u79fb\u52a8\u3002\u5176\u4e2d\uff0c\u4e00\u90e8\u5206\u8682\u8681\u5411 <strong>\u5de6</strong> \u79fb\u52a8\uff0c\u5176\u4ed6\u8682\u8681\u5411 <strong>\u53f3</strong> \u79fb\u52a8\u3002</p>\\n\\n<p>\u5f53\u4e24\u53ea\u5411 <strong>\u4e0d\u540c</strong> \u65b9\u5411\u79fb\u52a8\u7684\u8682\u8681\u5728\u67d0\u4e2a\u70b9\u76f8\u9047\u65f6\uff0c\u5b83\u4eec\u4f1a\u540c\u65f6\u6539\u53d8\u79fb\u52a8\u65b9\u5411\u5e76\u7ee7\u7eed\u79fb\u52a8\u3002\u5047\u8bbe\u66f4\u6539\u65b9\u5411\u4e0d\u4f1a\u82b1\u8d39\u4efb\u4f55\u989d\u5916\u65f6\u95f4\u3002</p>\\n\\n<p>\u800c\u5f53\u8682\u8681\u5728\u67d0\u4e00\u65f6\u523b <code>t</code> \u5230\u8fbe\u6728\u677f\u7684\u4e00\u7aef\u65f6\uff0c\u5b83\u7acb\u5373\u4ece\u6728\u677f\u4e0a\u6389\u4e0b\u6765\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570 <code>n</code> \u548c\u4e24\u4e2a\u6574\u6570\u6570\u7ec4 <code>left</code> \u4ee5\u53ca <code>right</code> \u3002\u4e24\u4e2a\u6570\u7ec4\u5206\u522b\u6807\u8bc6\u5411\u5de6\u6216\u8005\u5411\u53f3\u79fb\u52a8\u7684\u8682\u8681\u5728 <code>t = 0</code> \u65f6\u7684\u4f4d\u7f6e\u3002\u8bf7\u4f60\u8fd4\u56de\u6700\u540e\u4e00\u53ea\u8682\u8681\u4ece\u6728\u677f\u4e0a\u6389\u4e0b\u6765\u7684\u65f6\u523b\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p>&nbsp;</p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/06/17/ants.jpg\\" style=\\"height: 610px; width: 450px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 4, left = [4,3], right = [0,1]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u5982\u4e0a\u56fe\u6240\u793a\uff1a\\n-\u4e0b\u6807 0 \u5904\u7684\u8682\u8681\u547d\u540d\u4e3a A \u5e76\u5411\u53f3\u79fb\u52a8\u3002\\n-\u4e0b\u6807 1 \u5904\u7684\u8682\u8681\u547d\u540d\u4e3a B \u5e76\u5411\u53f3\u79fb\u52a8\u3002\\n-\u4e0b\u6807 3 \u5904\u7684\u8682\u8681\u547d\u540d\u4e3a C \u5e76\u5411\u5de6\u79fb\u52a8\u3002\\n-\u4e0b\u6807 4 \u5904\u7684\u8682\u8681\u547d\u540d\u4e3a D \u5e76\u5411\u5de6\u79fb\u52a8\u3002\\n\u8bf7\u6ce8\u610f\uff0c\u8682\u8681\u5728\u6728\u677f\u4e0a\u7684\u6700\u540e\u65f6\u523b\u662f t = 4 \u79d2\uff0c\u4e4b\u540e\u8682\u8681\u7acb\u5373\u4ece\u6728\u677f\u4e0a\u6389\u4e0b\u6765\u3002\uff08\u4e5f\u5c31\u662f\u8bf4\u5728 t = 4.0000000001 \u65f6\uff0c\u6728\u677f\u4e0a\u6ca1\u6709\u8682\u8681\uff09\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/06/17/ants2.jpg\\" style=\\"height: 101px; width: 639px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 7, left = [], right = [0,1,2,3,4,5,6,7]\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u8682\u8681\u90fd\u5411\u53f3\u79fb\u52a8\uff0c\u4e0b\u6807\u4e3a 0 \u7684\u8682\u8681\u9700\u8981 7 \u79d2\u624d\u80fd\u4ece\u6728\u677f\u4e0a\u6389\u843d\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/06/17/ants3.jpg\\" style=\\"height: 100px; width: 639px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 7, left = [0,1,2,3,4,5,6,7], right = []\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n<strong>\u89e3\u91ca\uff1a</strong>\u6240\u6709\u8682\u8681\u90fd\u5411\u5de6\u79fb\u52a8\uff0c\u4e0b\u6807\u4e3a 7 \u7684\u8682\u8681\u9700\u8981 7 \u79d2\u624d\u80fd\u4ece\u6728\u677f\u4e0a\u6389\u843d\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 9, left = [5], right = [4]\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n<strong>\u89e3\u91ca\uff1a</strong>t = 1 \u79d2\u65f6\uff0c\u4e24\u53ea\u8682\u8681\u5c06\u56de\u5230\u521d\u59cb\u4f4d\u7f6e\uff0c\u4f46\u79fb\u52a8\u65b9\u5411\u4e0e\u4e4b\u524d\u76f8\u53cd\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 6, left = [6], right = [0]\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 10^4</code></li>\\n\\t<li><code>0 &lt;= left.length &lt;= n + 1</code></li>\\n\\t<li><code>0 &lt;= left[i] &lt;= n</code></li>\\n\\t<li><code>0 &lt;= right.length &lt;= n + 1</code></li>\\n\\t<li><code>0 &lt;= right[i] &lt;= n</code></li>\\n\\t<li><code>1 &lt;= left.length + right.length &lt;= n + 1</code></li>\\n\\t<li><code>left</code> \u548c <code>right</code> \u4e2d\u7684\u6240\u6709\u503c\u90fd\u662f\u552f\u4e00\u7684\uff0c\u5e76\u4e14\u6bcf\u4e2a\u503c <strong>\u53ea\u80fd\u51fa\u73b0\u5728\u4e8c\u8005\u4e4b\u4e00</strong> \u4e2d\u3002</li>\\n</ul>\\n","title":"1503. \u6240\u6709\u8682\u8681\u6389\u4e0b\u6765\u524d\u7684\u6700\u540e\u4e00\u523b","relatedTags":["\u8111\u7b4b\u6025\u8f6c\u5f2f","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1503"}')}}]);